// ESP32 Touch + LEDC + DAC Lab
// ==============================
// Demonstrates three ESP32-only peripherals:
// 1. Capacitive Touch (touchRead on GPIO4 / T0)
// 2. LEDC Hardware PWM (two channels for LED brightness)
// 3. DAC Analog Output (8-bit true analog on GPIO25)
//
// Circuit:
//   GPIO18 -> 220R -> Blue LED -> GND   (LEDC channel 0)
//   GPIO19 -> 220R -> Green LED -> GND  (LEDC channel 1)
//   GPIO25 -> Buzzer -> GND             (DAC output)
//   GPIO4  = Touch input (T0) - just touch the wire!

#include <Arduino.h>

// --- Pin Assignments ---
const int TOUCH_PIN   = 4;    // T0 capacitive touch
const int LED_PIN_1   = 18;   // LEDC channel 0
const int LED_PIN_2   = 19;   // LEDC channel 1
const int DAC_PIN     = 25;   // DAC1 analog output

// --- LEDC Configuration ---
const int LEDC_CH0       = 0;
const int LEDC_CH1       = 1;
const int LEDC_FREQ      = 5000;  // 5 kHz PWM
const int LEDC_RESOLUTION = 8;    // 8-bit (0-255)

// --- Touch calibration ---
int touchBaseline = 0;
const int TOUCH_THRESHOLD = 40;  // delta below baseline = touch detected
const int SAMPLES = 8;

// Smoothed touch reading
int readTouchSmoothed() {
  long sum = 0;
  for (int i = 0; i < SAMPLES; i++) {
    sum += touchRead(TOUCH_PIN);
    delayMicroseconds(500);
  }
  return (int)(sum / SAMPLES);
}

void setup() {
  Serial.begin(115200);
  delay(300);

  Serial.println("================================");
  Serial.println("  ESP32 Touch + LEDC + DAC Lab");
  Serial.println("================================");
  Serial.println();

  // Configure LEDC PWM channels
  ledcSetup(LEDC_CH0, LEDC_FREQ, LEDC_RESOLUTION);
  ledcSetup(LEDC_CH1, LEDC_FREQ, LEDC_RESOLUTION);
  ledcAttachPin(LED_PIN_1, LEDC_CH0);
  ledcAttachPin(LED_PIN_2, LEDC_CH1);

  // Calibrate touch baseline (no touch)
  Serial.print("Calibrating touch sensor... ");
  touchBaseline = readTouchSmoothed();
  Serial.print("baseline = ");
  Serial.println(touchBaseline);
  Serial.println();
  Serial.println("Touch GPIO4 wire to see LEDs and DAC respond!");
  Serial.println("---");
}

void loop() {
  // Read capacitive touch
  int raw = readTouchSmoothed();
  int delta = touchBaseline - raw;
  if (delta < 0) delta = 0;

  // Map touch pressure to brightness (0-255)
  int brightness = map(delta, 0, TOUCH_THRESHOLD, 0, 255);
  brightness = constrain(brightness, 0, 255);

  // Drive LEDs with complementary brightness
  ledcWrite(LEDC_CH0, brightness);          // Blue LED: brighter with touch
  ledcWrite(LEDC_CH1, 255 - brightness);    // Green LED: dimmer with touch

  // DAC output mirrors touch pressure as analog voltage
  dacWrite(DAC_PIN, brightness);

  // Serial telemetry
  Serial.print("touch=");
  Serial.print(raw);
  Serial.print("  delta=");
  Serial.print(delta);
  Serial.print("  brightness=");
  Serial.print(brightness);
  Serial.print("  dac_mV=");
  Serial.println(map(brightness, 0, 255, 0, 3300));

  delay(100);
}
